const input = $input.first().json;
const hostname = input.hostname;
const NETBOX_URL = "http://10.1.1.104/api";
const NETBOX_TOKEN = "Token 6e517f4e4fd4b3f3d3de63770bd79e6faacf0fe4";

try {
  // Erst Devices suchen
  const devResp = await this.helpers.httpRequest({
    method: "GET",
    url: `${NETBOX_URL}/dcim/devices/?name=${encodeURIComponent(hostname)}`,
    headers: { Authorization: NETBOX_TOKEN },
    json: true
  });

  let host = null;
  let source = null;

  if (devResp.count > 0) {
    host = devResp.results[0];
    source = "device";
  } else {
    const vmResp = await this.helpers.httpRequest({
      method: "GET",
      url: `${NETBOX_URL}/virtualization/virtual-machines/?name=${encodeURIComponent(hostname)}`,
      headers: { Authorization: NETBOX_TOKEN },
      json: true
    });
    if (vmResp.count > 0) {
      host = vmResp.results[0];
      source = "vm";
    }
  }

  if (!host) {
    return [{ json: { found: false, hostname, error: `Host nicht in NetBox gefunden` } }];
  }

  const cf = host.custom_fields || {};
  return [{ json: {
    found: true, hostname, netbox_source: source, netbox_id: host.id,
    host_ip: host.primary_ip4 ? host.primary_ip4.address.split("/")[0] : null,
    host_ip6: host.primary_ip6 ? host.primary_ip6.address.split("/")[0] : null,
    platform: host.platform ? host.platform.slug : "unknown",
    platform_name: host.platform ? host.platform.name : "Unknown",
    ssh_user: cf.ssh_username || "root",
    ssh_password: cf.ssh_password || null,
    ssh_key_file: cf.ssh_key_file || null,
    maintenance_enabled: cf.maintenance_enabled !== false,
    maintenance_window: cf.maintenance_window || null,
    critical_system: cf.critical_system || false,
    device_role: host.role ? host.role.slug : (host.device_role ? host.device_role.slug : null),
    site: host.site ? host.site.name : null,
    api_key: cf.api_key || null
  }}];
} catch (e) {
  return [{ json: { found: false, hostname, error: "NetBox Error: " + e.message } }];
}

